previewCss:
.darma-loader-darma-custom-009 {
  width: 50px;
  aspect-ratio: 1.154;
  clip-path: polygon(50% 0, 100% 100%, 0 100%);
  position: relative;
}
.darma-loader-darma-custom-009::before {
  content: "";
  position: absolute;
  inset: -150% -100% -50%;
  background: repeating-conic-gradient(from 30deg, #FFABAB 0 60deg, #ABE4FF 0 120deg, #FF7373 0 180deg);
  animation: darma-loader-darma-custom-009-l9 2s infinite;
}
@keyframes darma-loader-darma-custom-009-l9 {
  0% { transform: rotate(0); }
  23%, 33% { transform: rotate(60deg); }
  56%, 66% { transform: rotate(120deg); }
  90%, 100% { transform: rotate(180deg); }
}

